  const search = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      query: targetQuery
    }
  });

  const outcomes = Array.isArray(search?.outcomes) ? search.outcomes : [];
  const ranked = pickTopSemanticCandidates({
    target: targetQuery,
    candidates: outcomes,
    requiredTerms: ["Paris Saint-Germain FC", "2026-04-08"],
    avoidTerms: ["draw", "to qualify", "to advance", "first half", "match result"],
    limit: 5
  });

  const selectedOutcome =
    ranked.find((item) => item?.tokenId) ||
    outcomes.find((item) => {
      const name = String(item?.name || "");
      return (
        name.includes("Paris Saint-Germain FC") &&
        name.includes("2026-04-08") &&
        item?.tokenId
      );
    }) ||
    null;

  if (!selectedOutcome?.tokenId) {
    return {
      error: "Could not deterministically resolve the requested market token.",
      targetQuery,
      searchMatchConfidence: search?.matchConfidence,
      searchEventTitle: search?.eventTitle,
      searchEventSlug: search?.eventSlug,
      candidateCount: outcomes.length,
      rankedCandidates: ranked.map((item) => ({
        name: item?.name,
        tokenId: item?.tokenId,
        conditionId: item?.conditionId,
        price: item?.price,
        volume: item?.volume
      }))
    };
  }

  const params = await callMcpSkill({
    toolId,
    toolName: "get_market_parameters",
    args: {
      tokenId: selectedOutcome.tokenId
    }
  });

  return {
    market: search?.eventTitle,
    searchMatchConfidence: search?.matchConfidence,
    selectedOutcome: {
      name: selectedOutcome.name,
      tokenId: selectedOutcome.tokenId,
      conditionId: selectedOutcome.conditionId,
      price: selectedOutcome.price,
      volume: selectedOutcome.volume
    },
    tradingParameters: {
      tickSize: params?.tickSize,
      feeRateBps: params?.feeRateBps,
      minOrderSize: params?.minOrderSize,
      negRisk: params?.negRisk
    },
    fetchedAt: params?.fetchedAt
  };
}

